  ('fire-eq-tech-moex-01765', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '有關瓦斯漏氣火警自動警報設備之警報裝置，下列何者錯誤？', '["瓦斯漏氣表示燈在一警報分區僅一室時，免設之", "瓦斯漏氣表示燈距離樓地板面之高度為4.5m以下", "瓦斯漏氣表示燈其亮度應在表示燈前方3m能明確識別", "警報音響，其音壓在距1m處，應有90分貝以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
